import{_ as a,o as i,c as n,a as s}from"./chunks/framework.8tiMeCK-.js";const u=JSON.parse('{"title":"第 10 章  永不消逝的回响：当内核决定放弃","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch10_1.md","filePath":"notes/linux_kernel_debugging/ch10_1.md","lastUpdated":null}'),t={name:"notes/linux_kernel_debugging/ch10_1.md"};function l(o,e,p,r,c,d){return i(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="第-10-章-永不消逝的回响-当内核决定放弃" tabindex="-1">第 10 章 永不消逝的回响：当内核决定放弃 <a class="header-anchor" href="#第-10-章-永不消逝的回响-当内核决定放弃" aria-label="Permalink to &quot;第 10 章  永不消逝的回响：当内核决定放弃&quot;">​</a></h1><h2 id="_10-1-技术准备与场地检查" tabindex="-1">10.1 技术准备与场地检查 <a class="header-anchor" href="#_10-1-技术准备与场地检查" aria-label="Permalink to &quot;10.1  技术准备与场地检查&quot;">​</a></h2><p>有一类问题，调试它们的过程就像是在没有黑匣子的飞机失坠现场寻找真相。</p><p>作为一名经常和内核打交道的工程师，你早晚会遇到那个时刻：屏幕停止滚动，键盘灯毫无规律地闪烁，最后一行日志冷酷地显示着 &quot;Kernel panic - not syncing&quot;。这一刻，往日里那个帮你打掩护、自动恢复错误的操作系统突然「摊牌」了——它拒绝继续执行，因为它发现再走下去只会带来更大的破坏。</p><p>这时候，最可怕的不是系统挂了，而是你两手空空。没有抓到崩溃时的内存镜像，不知道是哪个驱动最后触碰了红线，甚至不知道这到底是一次硬件故障还是软件逻辑的恶性死循环。</p><p>本章的核心任务，就是建立一套「死后验尸」的能力。我们将探讨内核在遇到无法挽回的错误时（Panic）会经历什么，那些形形色色的「死锁」检测器是如何工作的，以及如何通过 kexec 和 kdump 抓取现场。但在开始这场硬仗之前，我们得先确认手里的工具是否齐全，弹药是否充足。</p><h3 id="技术准备" tabindex="-1">技术准备 <a class="header-anchor" href="#技术准备" aria-label="Permalink to &quot;技术准备&quot;">​</a></h3><p>如果你读过第 1 章，那你应该已经装备好了。本章的战场环境和那章完全一致，我们就不重复造轮子了。</p><p>为了确保你能跟着我一起复现这些底层机制，你需要满足以下条件：</p><ol><li><p><strong>开发与构建环境</strong></p><ul><li>一个现代的 Linux 发行版（Ubuntu 20.04+ 或 Fedora 是推荐选择，毕竟新工具链对新内核特性的支持更好）。</li><li>完整的内核编译工具链（<code>gcc</code>, <code>make</code>, <code>bc</code> 等）。</li><li>足够的磁盘空间——如果你打算开启 kdump，你至少需要和物理内存大小相等的磁盘空间来保存崩溃转储。</li></ul></li><li><p><strong>实验环境</strong></p><ul><li>强烈建议使用 <strong>QEMU/LKVM</strong> 虚拟机。为什么？因为在本章的某些实验中，我们需要主动触发内核 Panic 或让 CPU 假死。在虚拟机里，这只是一个窗口关闭的问题；在物理机上，你可能面临强制重启的风险，更重要的是，物理机上的调试往往受限于硬件（比如串口波特率不够快，调试信息会丢）。</li><li>如果一定要在物理机上玩，请确保你有 JTAG 调试器或者至少有一个可靠的串口连接。</li></ul></li><li><p><strong>代码获取</strong></p></li></ol><p>所有的示例代码、补丁以及测试用的内核模块，都已经打包好了。你可以通过以下命令把它们拉到本地：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/PacktPublishing/Linux-Kernel-Debugging</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Linux-Kernel-Debugging</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这不仅仅是一堆代码，它是我们在这一章里用来「炸」内核的各种雷管。</p><hr><blockquote><p><strong>💡 译者注/作者提醒</strong>： 这里「技术准备」实际上对应原书的第一节。作为全书实战风格的延续，这一节虽然短，但它是一个「安全检查点」。在内核调试这个领域，环境不对，一切复现都会变成玄学。</p><p>请务必确认你的内核源码树已经准备好了，我们在后面修改 <code>panic.c</code> 和配置 <code>kexec</code> 时，需要直接动手编译和替换内核镜像。别偷懒，别直接用发行版自带的内核——那是给「用户」用的，不是给「内核黑客」用的。</p></blockquote><p>如果你都准备好了，那我们就正式进入内核最黑暗的时刻——从 Panic 开始。</p>`,16)])])}const g=a(t,[["render",l]]);export{u as __pageData,g as default};
